#include <bits/stdc++.h>
using namespace std;

const int N=1e3+3,mod=(1LL<<31)-1;

struct Edge{
    int to,val;
};

bool operator<(Edge x,Edge y){
    return x.val>y.val;
}

int n,m,dis[N],s[N],tot;
long long ans=1;
bool b[N];
vector<Edge> g[N];

void Dijkstra(){
    memset(dis,0x3f,sizeof(dis));
    priority_queue<Edge> q;
    dis[1]=0,s[1]=1;
    q.push({1,0});
    while(q.size()){
        while(q.size() && b[q.top().to])
            q.pop();
        if(q.empty())
            break;
        int x=q.top().to;
        q.pop(),b[x]=1,tot++;
        ans=ans*s[x]%mod;
        for(Edge y:g[x])
            if(dis[y.to]>dis[x]+y.val){
                dis[y.to]=dis[x]+y.val,s[y.to]=1;
                q.push({y.to,dis[y.to]});
            }else if(dis[y.to]==dis[x]+y.val)
                s[y.to]++;
    }
    if(tot<n)
        printf("0");
    else
        printf("%lld",ans);
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v,w;i<=m;i++){
        scanf("%d%d%d",&u,&v,&w);
        g[u].push_back({v,w});
        g[v].push_back({u,w});
    }
    Dijkstra();
    return 0;
}
